<?php\n\namespace App\Services;\n\class SettingsService {\n    private static $data = [];\n\n    public function __construct() {\n        // Initialize with some dummy data on load\n        self::[1] = [\n            'theme' => 'dark',\n            'notifications' => true\n        ];\n    }\n\n    public function get(int $userId) {\n        return self::[$userId] ?? null;\n    }\n\n    // Processes and saves settings data\n    public function save(array $formData): bool {\n        if (!isset($formData['theme']) || !isset($formData['notifications'])) {\n            return false; // Incomplete form data\n        }\n        \n        self::[1] = [\n            'theme' => $_POST['theme'],\n            'notifications' => isset($_POST['notifications']) && $_POST['notifications'] == 'on'\n        ];\n        return true;\n    }\n}
